def find_maximum(numbers):
    if not numbers:
        return None  # Handle empty list case

    max_value = numbers[0]  # Assume the first number is the largest initially

    for number in numbers:
        if number > max_value:  # Check if current number is greater than the current max
            max_value = number  # Update max_value if condition is true

    return max_value  # Return the largest number found in the list

