def unique_paths(m, n):
    # Assuming default initial values for grid dimensions
    dp = [[1] * n for _ in range(m)]  # Setting default grid with all paths initialized to 1

    for i in range(1, m):
        for j in range(1, n):
            dp[i][j] = dp[i - 1][j] + dp[i][j - 1]  # Reference to configurations based on previous paths

    return dp[m - 1][n - 1]

